(()=>{const b='';const bin=atob(b);const arr=new Uint8Array(bin.length);for(let i=0;i<bin.length;i++)arr[i]=bin.charCodeAt(i);const file=new File([arr],'ig1.png',{type:'image/png'});const dt=new DataTransfer();dt.items.add(file);const inp=document.querySelector('input[type="file"]');inp.files=dt.files;inp.dispatchEvent(new Event('change',{bubbles:true}));return 'injected size='+file.size;})()
